import{_ as a,c as e,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"高度な設定：高度な機能の完全解説 | Antigravity-Manager","description":"Antigravity-Manager の高度な設定方法を学びます。アカウントスケジューリング、モデルルーティング、クォータガバナンス、モニタリング統計など高度な機能をマスターします。","frontmatter":{"title":"高度な設定：高度な機能の完全解説 | Antigravity-Manager","order":300,"sidebarTitle":"システムを本番環境レベルにアップグレード","subtitle":"高度な設定：高度な機能の完全解説","description":"Antigravity-Manager の高度な設定方法を学びます。アカウントスケジューリング、モデルルーティング、クォータガバナンス、モニタリング統計など高度な機能をマスターします。"},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"ja/lbjlaq/Antigravity-Manager/advanced/index.md"};function d(i,t,o,l,p,c){return s(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="高度な設定" tabindex="-1">高度な設定 <a class="header-anchor" href="#高度な設定" aria-label="Permalink to &quot;高度な設定&quot;">​</a></h1><p>この章では Antigravity Tools の高度な機能を深く解説します：設定管理、セキュリティポリシー、アカウントスケジューリング、モデルルーティング、クォータガバナンス、モニタリング統計、およびサーバーデプロイメント戦略。これらをマスターすると、Antigravity Tools を「使える」から「使いやすく、安定した、運用可能」レベルにアップグレードできます。</p><h2 id="この章に含まれる内容" tabindex="-1">この章に含まれる内容 <a class="header-anchor" href="#この章に含まれる内容" aria-label="Permalink to &quot;この章に含まれる内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td><a href="./config/">設定完全解説</a></td><td>AppConfig/ProxyConfig の完全なフィールド、保存場所とホットリロードの意味論</td></tr><tr><td><a href="./security/">セキュリティとプライバシー</a></td><td><code>auth_mode</code>、<code>allow_lan_access</code> とセキュリティベースライン設計</td></tr><tr><td><a href="./scheduling/">高可用スケジューリング</a></td><td>ローテーション、固定アカウント、スティッキーセッションと失敗時リトライメカニズム</td></tr><tr><td><a href="./model-router/">モデルルーティング</a></td><td>カスタムマッピング、ワイルドカード優先順位とプリセット戦略</td></tr><tr><td><a href="./quota/">クォータガバナンス</a></td><td>Quota Protection + Smart Warmup の組み合わせ戦術</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>リクエストログ、フィルタリング、詳細復元とエクスポート</td></tr><tr><td><a href="./token-stats/">Token Stats</a></td><td>コスト視点の統計指標とチャート解説</td></tr><tr><td><a href="./context-compression/">長時間セッションの安定性</a></td><td>コンテキスト圧縮、署名キャッシュとツール結果圧縮</td></tr><tr><td><a href="./system/">システム能力</a></td><td>多言語/テーマ/更新/起動時自動起動/HTTP API Server</td></tr><tr><td><a href="./deployment/">サーバーデプロイメント</a></td><td>Docker noVNC vs Headless Xvfb 選定と運用</td></tr></tbody></table><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推奨順序</p><p>この章の内容は多岐にわたるため、以下のモジュールに分けて学習することを推奨します：</p></div><p><strong>第一フェーズ：設定とセキュリティ（必須）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>設定完全解説 → セキュリティとプライバシー</span></span>
<span class="line"><span>config      security</span></span></code></pre></div><p>まず設定システムを理解（どれを再起動が必要か、どれがホットリロード可能か）、その後セキュリティ設定を学習（特に LAN/インターネットに公開する場合）。</p><p><strong>第二フェーズ：スケジューリングとルーティング（推奨）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高可用スケジューリング → モデルルーティング</span></span>
<span class="line"><span>scheduling    model-router</span></span></code></pre></div><p>最小のアカウント数で最大の安定性を得る方法を学び、その後モデルルーティングでアップストリームの変動をシールド。</p><p><strong>第三フェーズ：クォータとモニタリング（必要に応じて）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>クォータガバナンス → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota        monitoring      token-stats</span></span></code></pre></div><p>クォータの知覚な消費を防ぎ、呼び出しブラックボックスを観測可能なシステムに変え、コストを定量化して最適化。</p><p><strong>第四フェーズ：安定性とデプロイメント（高度）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>長時間セッションの安定性 → システム能力 → サーバーデプロイメント</span></span>
<span class="line"><span>context-compression  system    deployment</span></span></code></pre></div><p>長時間セッションの隠れた問題を解決し、クライアントをより製品に近づけ、最後にサーバーデプロイメントを学習。</p><p><strong>クイック選択</strong>：</p><table tabindex="0"><thead><tr><th>あなたのシナリオ</th><th>まず見るべき</th></tr></thead><tbody><tr><td>複数アカウントローテーションが不安定</td><td><a href="./scheduling/">高可用スケジューリング</a></td></tr><tr><td>特定のモデル名を固定したい</td><td><a href="./model-router/">モデルルーティング</a></td></tr><tr><td>クォータがいつも尽きる</td><td><a href="./quota/">クォータガバナンス</a></td></tr><tr><td>リクエストログを見たい</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>Token 消費を統計したい</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>長い会話で頻繁にエラー</td><td><a href="./context-compression/">長時間セッションの安定性</a></td></tr><tr><td>LAN に公開したい</td><td><a href="./security/">セキュリティとプライバシー</a></td></tr><tr><td>サーバーにデプロイしたい</td><td><a href="./deployment/">サーバーデプロイメント</a></td></tr></tbody></table><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前に確認してください</p><ul><li><a href="./../start/">クイックスタート</a> 章を完了済み（少なくともインストール、アカウント追加、リバースプロキシ起動を完了）</li><li><a href="./../platforms/">プラットフォームと統合</a> の少なくとも 1 つのプロトコル接続を完了（例：OpenAI または Anthropic）</li><li>ローカルリバースプロキシが正常にリクエストに応答できる</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を学習した後、以下を続けて学習できます：</p><ul><li><a href="./../faq/">よくある質問</a>：401/404/429/ストリーミング中断などの問題が発生した場合のトラブルシューティングガイド</li><li><a href="./../appendix/">付録</a>：エンドポイント早見表、データモデル、z.ai 能力境界などの参考資料</li></ul>`,25)])])}const u=a(n,[["render",d]]);export{g as __pageData,u as default};
